function openChat(id){state.currentChat=id;state.unread[id]=0;document.getElementById("appContainer").classList.add("chatOpen");const c=state.contacts[id];const nameEl=document.getElementById("chatHeaderName");const idEl=document.getElementById("chatHeaderId");document.getElementById("emptyChat").style.display="none";nameEl.style.display=idEl.style.display="block";nameEl.textContent=c.name;idEl.textContent=c.publicId.slice(0,16)+"…";updateChatRelayInfo(id);const menuBtn=document.getElementById("contactMenuBtn");if(c.publicId===state.publicId){menuBtn.classList.remove("visible");}else{menuBtn.classList.add("visible");document.getElementById("blockToggleBtn").textContent=c.blocked?"UNBLOCK":"BLOCK";}
document.getElementById("contactDropdown").classList.remove("open");renderContactList();renderMessages();document.getElementById("chatInput").focus();}
function renderMessages(){const container=document.getElementById("chatMessages");container.innerHTML="";if(!state.currentChat)return;const msgs=state.contacts[state.currentChat]?.messages||[];const visible=msgs.filter(m=>m.type!=="reaction");if(!visible.length){container.innerHTML='<div style="color:var(--muted);font-size:12px;text-align:center;margin-top:40px;letter-spacing:0.1em">no messages yet</div>';return;}
visible.forEach(m=>{const mine=m.from===state.publicId;const wrap=document.createElement("div");wrap.style.cssText="display:flex;flex-direction:column;align-items:"+(mine?"flex-end":"flex-start");const bubble=document.createElement("div");bubble.className="message "+(mine?"mine":"theirs")+(m.valid===false?" invalid":"");if(m.type==="audio"){if(m.expired||!audioCache[m.id]){bubble.innerHTML=`<span style="color:var(--muted);font-size:12px">🎤 audio message (not available)</span>`;}else{const audio=document.createElement("audio");audio.controls=true;audio.style.maxWidth="200px";getAudioUrl(m.id).then(url=>{if(url){audio.src=url;audio.addEventListener("ended",()=>{URL.revokeObjectURL(url);audio.removeAttribute("src");},{once:true});}else{bubble.innerHTML=`<span style="color:var(--muted);font-size:12px">🎤 audio message (unavailable)</span>`;}});bubble.appendChild(audio);}}else if(m.type==="image"){if(!imageCache[m.id]){bubble.innerHTML=`<span style="color:var(--muted);font-size:12px">🖼 image (not available)</span>`;}else{const img=document.createElement("img");img.style.cssText="max-width:200px;display:block;border-radius:2px";img.alt="image";(async()=>{try{const plain=await decryptObject(state.encKey,imageCache[m.id].encBlob);const bytes=Uint8Array.from(atob(plain.data),c=>c.charCodeAt(0));const blob=new Blob([bytes],{type:plain.mimeType});img.src=URL.createObjectURL(blob);}catch(e){bubble.innerHTML=`<span style="color:var(--muted);font-size:12px">🖼 image (unavailable)</span>`;}})();bubble.appendChild(img);}}else{bubble.innerHTML=linkify(m.text||"");}
const meta=document.createElement("div");meta.className="msgMeta";const d=new Date(m.ts);meta.textContent=d.toLocaleDateString([],{month:"short",day:"numeric"})+" "
+d.toLocaleTimeString([],{hour:"2-digit",minute:"2-digit"})
+(m.valid===false?" · ⚠ unverified":"");bubble.appendChild(buildReactionRow(m.id,msgs,mine));wrap.appendChild(bubble);wrap.appendChild(meta);container.appendChild(wrap);});container.scrollTop=container.scrollHeight;}
function openModal(){document.getElementById("myKeyDisplay").textContent=state.shareableKey;document.getElementById("modalContactName").value="";document.getElementById("modalContactKey").value="";document.getElementById("scanResult").textContent="";buildMyQR(state.shareableKey);switchTab("show");document.getElementById("modalOverlay").classList.add("open");}
function closeModal(){if(scannerRunning)stopScanner();document.getElementById("modalOverlay").classList.remove("open");}
function openExportModal(){document.getElementById("exportPassphrase").value="";document.getElementById("exportStatus").textContent="";document.getElementById("exportOverlay").classList.add("open");document.getElementById("exportPassphrase").focus();}
function closeExportModal(){document.getElementById("exportOverlay").classList.remove("open");}
function contactAction(action){document.getElementById("contactDropdown").classList.remove("open");const c=state.contacts[state.currentChat];if(!c)return;const title=document.getElementById("contactActionTitle");const body=document.getElementById("contactActionBody");const btns=document.getElementById("contactActionBtns");body.innerHTML=btns.innerHTML="";if(action==="edit"){title.textContent="EDIT CONTACT";const nameInput=document.createElement("input");nameInput.value=c.name;nameInput.placeholder="contact name";nameInput.autocomplete="off";const keyInput=document.createElement("input");keyInput.placeholder="paste new key to update (optional)";keyInput.autocomplete="off";keyInput.spellcheck=false;body.appendChild(nameInput);body.appendChild(keyInput);btns.innerHTML='<button class="btn-cancel" onclick="closeContactAction()">CANCEL</button>'+'<button class="btn-confirm" id="contactActionConfirm">SAVE</button>';document.getElementById("contactActionOverlay").classList.add("open");nameInput.focus();document.getElementById("contactActionConfirm").onclick=async()=>{const val=nameInput.value.trim();if(!val)return;c.name=val;c.lastStateChange=Date.now();const newKey=keyInput.value.trim();if(newKey){try{const parts=newKey.split(".");if(parts.length<2||parts.length>3)throw new Error("invalid key format");const encKeyBytes=base64ToRaw(parts[0]);const signPublicKey=base64ToRaw(parts[1]);if(encKeyBytes.length!==32||signPublicKey.length!==32)throw new Error("invalid key length");c.shareableKey=newKey;c.encKey=await importEncKey(encKeyBytes);c.signPublicKey=signPublicKey;if(parts.length===3&&parts[2])c.lastRelay=atob(parts[2]);mlog.info(`CONTACT    key updated for ${c.name}  ${pid(c.publicId)}${c.lastRelay?" wss="+c.lastRelay:""}`);}catch(e){mlog.warn("CONTACT    key update failed: "+e.message);return;}}
await saveContacts();document.getElementById("chatHeaderName").textContent=val;renderContactList();closeContactAction();};nameInput.onkeydown=(e)=>{if(e.key==="Enter")document.getElementById("contactActionConfirm").click();};}else if(action==="block"){const blocking=!c.blocked;title.textContent=blocking?"BLOCK CONTACT":"UNBLOCK CONTACT";const hint=document.createElement("div");hint.className="hint";hint.textContent=blocking?"You will stop receiving messages from this contact. You can unblock them at any time.":"You will start receiving messages from this contact again.";body.appendChild(hint);btns.innerHTML='<button class="btn-cancel" onclick="closeContactAction()">CANCEL</button>'+'<button class="btn-confirm" id="contactActionConfirm">'+(blocking?"BLOCK":"UNBLOCK")+'</button>';document.getElementById("contactActionOverlay").classList.add("open");document.getElementById("contactActionConfirm").onclick=async()=>{c.blocked=blocking;c.lastStateChange=Date.now();if(blocking){c.messages=[];if(state.peerBackups[c.publicId]){delete state.peerBackups[c.publicId];savePeerBackups();mlog.info(`BLOCK      wiped backup  id=${pid(c.publicId)}`);}
mlog.info(`BLOCK      wiped messages  id=${pid(c.publicId)}`);}
await saveContacts();document.getElementById("blockToggleBtn").textContent=c.blocked?"UNBLOCK":"BLOCK";renderContactList();closeContactAction();};}else if(action==="delete"){title.textContent="DELETE CONTACT";const hint=document.createElement("div");hint.className="hint";hint.innerHTML="<strong style='color:var(--danger)'>Only delete if their key is permanently lost.</strong><br><br>"+"If they might still be reachable, use <em>Block</em> instead — "+"deleted contacts cannot be recovered without their key.";body.appendChild(hint);btns.innerHTML='<button class="btn-cancel" onclick="closeContactAction()">CANCEL — KEEP</button>'+'<button class="btn-confirm" style="background:var(--danger);border-color:var(--danger)" id="contactActionConfirm">DELETE</button>';document.getElementById("contactActionOverlay").classList.add("open");document.getElementById("contactActionConfirm").onclick=async()=>{delete state.contacts[state.currentChat];state.currentChat=null;document.getElementById("emptyChat").style.display="block";document.getElementById("chatHeaderName").style.display="none";document.getElementById("chatHeaderId").style.display="none";document.getElementById("contactMenuBtn").classList.remove("visible");document.getElementById("chatMessages").innerHTML="";await saveContacts();renderContactList();closeContactAction();};}}
function closeContactAction(){document.getElementById("contactActionOverlay").classList.remove("open");}
document.getElementById("loginButton").onclick=async(e)=>{e.preventDefault();const name=document.getElementById("inputName").value.trim();const pass=document.getElementById("inputPassphrase").value;const status=document.getElementById("loginStatus");if(!name||!pass){status.textContent="name and passphrase required";return;}
const btn=document.getElementById("loginButton");btn.disabled=true;status.textContent="deriving keys…";try{const master=await deriveMasterSecret(name,pass);const keys=await hkdfExpand(master);state.user=name;state.keys=keys;state.publicId=await derivePublicId(keys.encryptionKey);const signPublicKey=ed25519.getPublicKey(keys.signingKeySeed);state.shareableKey=rawToBase64(keys.encryptionKey)+"."+rawToBase64(signPublicKey);state.cryptoKey=await importEncKey(keys.backupKey);state.encKey=await importEncKey(keys.encryptionKey);const k128=await derive128Keys(name,pass);state.encKey128=await importEncKey128(k128.encKey128);state.signKey128=await importEncKey128(k128.signKey128);state.publicId128=await derivePublicId(k128.encKey128);state.shareableKey128=rawToBase64(k128.encKey128)+"."+rawToBase64(k128.signKey128);mlog.info(`LOGIN128   ${pid(state.publicId128)}`);await loadContacts();if(!state.contacts[state.publicId]){const parts=state.shareableKey.split(".");const encKeyBytes=base64ToRaw(parts[0]);state.contacts[state.publicId]={name:state.user+" (me)",publicId:state.publicId,shareableKey:state.shareableKey,encKey:await importEncKey(encKeyBytes),signPublicKey,messages:[]};}else{state.contacts[state.publicId].shareableKey=state.shareableKey;state.contacts[state.publicId].signPublicKey=signPublicKey;}
loadPeerBackups();document.getElementById("loginScreen").style.display="none";document.getElementById("appContainer").style.display="flex";mlog.info(`LOGIN      ${name}  ${pid(state.publicId)}`);renderContactList();connectSignal();schedulePoll();}catch(e){status.textContent=e.message||"error during login";btn.disabled=false;}};document.getElementById("addContactBtn").onclick=openModal;document.getElementById("showBlockedBtn").onclick=toggleShowBlocked;document.getElementById("modalCancel").onclick=closeModal;document.getElementById("exportBtn").onclick=openExportModal;document.getElementById("exportCancel").onclick=closeExportModal;document.getElementById("syncBtn").onclick=()=>{if(state.currentChat)initiateExchange(state.currentChat);};document.getElementById("myKeyBox").onclick=()=>navigator.clipboard.writeText(state.shareableKey).catch(()=>{});document.getElementById("contactMenuBtn").onclick=(e)=>{e.stopPropagation();document.getElementById("contactDropdown").classList.toggle("open");};document.addEventListener("click",()=>{document.getElementById("contactDropdown").classList.remove("open");});document.getElementById("modalOverlay").onclick=(e)=>{if(e.target===document.getElementById("modalOverlay"))closeModal();};document.getElementById("exportOverlay").onclick=(e)=>{if(e.target===document.getElementById("exportOverlay"))closeExportModal();};document.getElementById("modalConfirm").onclick=async()=>{const name=document.getElementById("modalContactName").value.trim();const key=document.getElementById("modalContactKey").value.trim();const legacy=document.getElementById("tabLegacy")?.classList.contains("active");if(!name||!key)return;const ok=legacy?await addContact128(name,key):await addContact(name,key);if(ok)closeModal();};document.getElementById("exportConfirm").onclick=async()=>{const pass=document.getElementById("exportPassphrase").value;const status=document.getElementById("exportStatus");if(!pass){status.textContent="passphrase required";return;}
try{status.textContent="encrypting…";await exportBackup(pass);status.textContent="exported!";setTimeout(closeExportModal,1200);}
catch(e){status.textContent="export failed: "+e.message;}};document.getElementById("importConfirm").onclick=()=>{const input=Object.assign(document.createElement("input"),{type:"file",accept:".json"});input.onchange=async()=>{const file=input.files[0];const pass=document.getElementById("exportPassphrase").value;const status=document.getElementById("exportStatus");if(!file)return;if(!pass){status.textContent="enter passphrase first";return;}
try{status.textContent="decrypting…";await importBackup(file,pass);status.textContent="restored!";setTimeout(closeExportModal,1200);}
catch(e){status.textContent="restore failed — wrong passphrase or file?";}};input.click();};document.getElementById("sendButton").onclick=sendMessage;document.getElementById("chatInput").onkeydown=(e)=>{if(e.key==="Enter"&&!e.shiftKey){e.preventDefault();sendMessage();}};const audioBtn=document.getElementById("audioBtn");if(audioBtn){audioBtn.addEventListener("mousedown",startAudioRecord);audioBtn.addEventListener("mouseup",stopAudioRecord);audioBtn.addEventListener("touchstart",e=>{e.preventDefault();startAudioRecord();});audioBtn.addEventListener("touchend",e=>{e.preventDefault();stopAudioRecord();});}
const imageBtn=document.getElementById("imageBtn");const imageInput=document.getElementById("imageInput");if(imageBtn&&imageInput){imageBtn.addEventListener("click",()=>{if(state.currentChat)imageInput.click();});imageInput.addEventListener("change",()=>{const file=imageInput.files[0];if(file){sendImageMessage(file);imageInput.value="";}});}
